   346→void NCCLComm::abort(std::optional<std::string> commFailureReason) {
   347→  LockType lock(mutex_);
   348→  at::cuda::OptionalCUDAGuard gpuGuard(deviceIndex_);
   349→#ifdef ENABLE_NCCL_ERROR_CHECKING
   350→  if (aborted_ && !initialized_) {
   351→    // Should not abort twice.
   352→    return;
   353→  }
   354→
   355→#ifdef NCCL_HAS_COMM_REGISTER
   356→  // Deregister all registered segments before aborting.
   357→  for (auto& it : registeredSegmentHandles_) {
   358→    void* handle = it.second;
   359→    C10D_NCCL_CHECK(
   360→        ::ncclCommDeregister(ncclComm_, handle),
   361→        c10::str(
   362→            "Failed to deregister segment handle ",
   363→            handle,
   364→            " on ncclComm_ ",
   365→            ncclComm_));
   366→  }
   367→  registeredSegmentHandles_.clear();
   368→#endif
   369→
   370→  // Set true failure reason if provided by ProcessGroupNCCL (e.g. work
   371→  // timeout)
   372→  commFailureReason_ = commFailureReason;
   373→  LOG(INFO) << "Aborting ncclComm_ " << ncclComm_ << " with reason: "
   374→            << (commFailureReason ? *commFailureReason
   375→                                  : "No abort reason provided.");
   376→#ifndef NCCL_HAS_COMM_NONBLOCKING
   377→  C10D_NCCL_CHECK(::ncclCommAbort(ncclComm_), commFailureReason_);
   378→#else
   379→  C10D_NCCL_CHECK_TIMEOUT(
   380→      ::ncclCommAbort(ncclComm_), ncclComm_, commFailureReason_);
   381→#endif
   382→  aborted_ = true;
   383→  ncclComm_ = nullptr;
   384→
   385→  // Set an appropriate error so that we avoid using the communicator.
   386→  if (ncclAsyncErr_ == ncclSuccess) {
   387→    ncclAsyncErr_ = ncclSystemError;
   388→  }
   389→#else
   390→  // This is a NOOP, if error checks are disabled.
   391→  return;
   392→#endif
   393→}
