   612→size_t hashTensors(const std::vector<at::Tensor>& tensors) {
   613→  size_t hash = 0;
   614→  for (auto& tensor : tensors) {
   615→    if (tensor.numel() > 0 && tensor.storage()) {
   616→      size_t data_size = tensor.storage().nbytes();
   617→      if (data_size > 0 && tensor.storage().data_ptr()) {
   618→        auto src = static_cast<const char*>(tensor.storage().data_ptr().get());
   619→        std::vector<char> dst(data_size);
   620→        // This is needed so that we trigger a device synchronization so we can
   621→        // get the collective finished if launched on GPU and hash its output.
   622→        AT_CUDA_CHECK(
   623→            cudaMemcpy(dst.data(), src, data_size, cudaMemcpyDeviceToHost));
   624→        for (size_t i = 0; i < data_size; ++i) {
   625→          // Update the hash for each byte in the tensor
   626→          hash = c10::hash_combine(hash, c10::get_hash(dst[i], data_size));
   627→        }
   628→      }
   629→    }
   630→  }
   631→  return hash;
   632→}
